   290	        protected async Task SetCustomizedTextAsync(string text, bool updateValue = true,
   291	            IReadOnlyList<string?>? selectedConvertedValues = null,
   292	            Func<IReadOnlyList<string?>?, string>? multiSelectionTextFunc = null)
   293	        {
   294	            // The Text property of the control is updated
   295	            var customText = multiSelectionTextFunc?.Invoke(selectedConvertedValues);
   296	            await SetTextCoreAsync(customText);
   297	
   298	            // The comparison is made on the multiSelectionText variable
   299	            if (_multiSelectionText != text)
   300	            {
   301	                _multiSelectionText = text;
   302	                if (!string.IsNullOrWhiteSpace(_multiSelectionText))
   303	                {
   304	                    Touched = true;
   305	                }
   306	
   307	                if (updateValue)
   308	                {
   309	                    await UpdateValuePropertyAsync(false);
   310	                }
   311	            }
   312	        }
