   325	        protected override Task UpdateValuePropertyAsync(bool updateText)
   326	        {
   327	            // For MultiSelection of non-string T's we don't update the Value!!!
   328	            if (typeof(T) == typeof(string) || !MultiSelection)
   329	            {
   330	                base.UpdateValuePropertyAsync(updateText);
   331	            }
   332	
   333	            return Task.CompletedTask;
   334	        }
   335	
   336	        protected override Task UpdateTextPropertyAsync(bool updateValue)
   337	        {
   338	            // when multiselection is true, we return
   339	            // a comma separated list of selected values
   340	            if (MultiSelectionTextFunc != null)
   341	            {
   342	                return MultiSelection
   343	                    ? SetCustomizedTextAsync(string.Join(Delimiter, _selectedValues.Select(ConvertSet)),
   344	                        selectedConvertedValues: _selectedValues.Select(ConvertSet).ToList(),
   345	                        multiSelectionTextFunc: MultiSelectionTextFunc)
   346	                    : base.UpdateTextPropertyAsync(updateValue);
   347	            }
   348	
   349	            return MultiSelection
   350	                ? SetTextAndUpdateValueAsync(string.Join(Delimiter, _selectedValues.Select(ConvertSet)))
   351	                : base.UpdateTextPropertyAsync(updateValue);
   352	        }
